-- 2. DDL - Create tables with Oracle-compliant datatypes

CREATE TABLE dim_soc_taxonomy (
    soc_code VARCHAR2(10) PRIMARY KEY,
    soc_title VARCHAR2(150) NOT NULL,
    category VARCHAR2(50) NOT NULL
);

CREATE TABLE dim_ashe_salary (
    soc_code VARCHAR2(10) NOT NULL,
    soc_title VARCHAR2(150),
    category VARCHAR2(50),
    region VARCHAR2(50) NOT NULL,
    median_salary NUMBER(10),
    mean_salary NUMBER(10),
    hourly_median NUMBER(6,2),
    CONSTRAINT pk_dim_ashe PRIMARY KEY (soc_code, region)
);

CREATE TABLE dim_labor_supply (
    soc_code VARCHAR2(10) NOT NULL,
    soc_title VARCHAR2(150),
    category VARCHAR2(50),
    region VARCHAR2(50) NOT NULL,
    employed_count NUMBER(10),
    unemployed_count NUMBER(10),
    retirement_risk_rate NUMBER(5,3),
    annual_grad_supply NUMBER(10),
    CONSTRAINT pk_dim_supply PRIMARY KEY (soc_code, region)
);

CREATE TABLE dim_extracted_skills (
    job_title VARCHAR2(100) NOT NULL,
    soc_code VARCHAR2(10) PRIMARY KEY,
    extracted_skills VARCHAR2(500),
    skills_count NUMBER(5)
);

CREATE TABLE fact_employees (
    employee_id VARCHAR2(10) PRIMARY KEY,
    name VARCHAR2(100) NOT NULL,
    age NUMBER(3) NOT NULL,
    department VARCHAR2(50) NOT NULL,
    job_title VARCHAR2(100) NOT NULL,
    salary NUMBER(10) NOT NULL,
    region VARCHAR2(50) NOT NULL,
    soc_code VARCHAR2(10) NOT NULL,
    skills VARCHAR2(500),
    tenure_years NUMBER(4,1) NOT NULL,
    performance_rating NUMBER(1),
    retirement_risk VARCHAR2(10),
    succession_readiness VARCHAR2(50),
    CONSTRAINT fk_employees_soc FOREIGN KEY (soc_code) REFERENCES dim_soc_taxonomy(soc_code)
);

CREATE TABLE fact_market_vacancies (
    job_id VARCHAR2(20) PRIMARY KEY,
    title VARCHAR2(150) NOT NULL,
    description VARCHAR2(500),
    created_date DATE,
    company VARCHAR2(100),
    region VARCHAR2(50) NOT NULL,
    soc_code VARCHAR2(10) NOT NULL,
    salary_min NUMBER(10),
    salary_max NUMBER(10),
    category VARCHAR2(50) NOT NULL,
    skills_required VARCHAR2(500),
    source VARCHAR2(20) NOT NULL,
    CONSTRAINT fk_vacancies_soc FOREIGN KEY (soc_code) REFERENCES dim_soc_taxonomy(soc_code)
);

